sql:
WITH high_score_games AS (
    SELECT game_id FROM games WHERE home_score > 10
),
game_plays AS (
    SELECT play_id FROM plays WHERE game_id IN (SELECT game_id FROM high_score_games)
)
SELECT shots.* 
FROM shots
WHERE play_id IN (SELECT play_id FROM game_plays);

SELECT game_id, win_prob
FROM plays
WHERE play_id = 1;

SELECT game_id, COUNT(play_id) AS total_plays
FROM plays
GROUP BY game_id;

external_knowledge:
- 'initial game' refers to the game with game_id = 1;
- 'standout player' is the player with the top aggregate score;
- 'aggregate score' is the sum of score values for each player in that game.

